#!/usr/bin/perl
use strict;
use warnings;

# Get the comment from the query string
my $comment = $ENV{'QUERY_STRING'};

# Escape any potentially harmful characters to prevent XSS
$comment =~ s/&/&amp;/g;
$comment =~ s/</&lt;/g;
$comment =~ s/>/&gt;/g;

print "Content-type: text/html\n\n";
print "<div>$comment</div>";